// GUARDiAN GATE — idempotency hash + field/risk validation.
// Output: decision + guardian{status,reason,risk_score} + execution_hash.
const raw = $input.first().json;
const d = raw.body || raw;
function hash(str){let h=5381;for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h=h&0xffffffff;}return 'exh_'+(h>>>0).toString(16);}
const required = ['decision_id','domain','recommended_action','routing'];
const missing = required.filter(k => d[k] == null);
const systems = (d.routing && d.routing.systems) || [];
const execution_hash = hash(JSON.stringify({ id: d.decision_id, sys: systems, action: d.recommended_action }));
let status='approved', reason='passed guardian checks', risk=0.2;
if (missing.length) { status='rejected'; reason='missing fields: '+missing.join(', '); risk=1.0; }
else if (String(d.domain).toLowerCase() !== 'property') { status='rejected'; reason='Execution Fabric v1 is Property-only'; risk=0.9; }
else if (/financial|pricing|rent|fee/i.test(d.recommended_action)) { status='requires_review'; reason='financial change requires human approval'; risk=0.7; }
// NOTE: real idempotency dedupe should look up execution_hash in a persistent store
// (Notion/Redis) and set status='rejected' (duplicate) if already executed.
return [{ json: { ...d, guardian: { status, reason, risk_score: risk }, execution_hash } }];

// ── CONTRACT VALIDATOR ───────────────────────────────────────────────
// Inline, READ-ONLY snapshot of the frozen Enterprise Contract Registry v2.0
// (outputs/contracts/, frozen 2026-06-22). n8n cannot import repo files, so the
// constitution is EMBEDDED here. If the registry version bumps, re-sync this block
// (it is the only place the runtime can read the contracts).
//
// Enforces what GUARDiAN does NOT: contract conformance of the decision BEFORE
// execution. Invalid => hard reject (status REJECTED_CONTRACT_VIOLATION), skip
// execution, still written to the audit log. Contracts CONTROL whether execution
// is allowed — they no longer merely describe behavior.
const CONTRACTS = {
  registry: 'Enterprise Contract Registry',
  version: '2.0',
  frozen_at: '2026-06-22',
  // domain-registry.json — immutable domain IDs (id is the join key, never the display name)
  domain_ids: ['built','digital','human','industrial','governance','enterprise','property','innovation','energy','knowledge'],
  domain_names: { // lowercased display name -> id (to catch name-used-as-id)
    'built environment & physical assets':'built','digital systems & software execution':'digital',
    'human services & care systems':'human','industrial & supply chain systems':'industrial',
    'governance & public systems':'governance','enterprise business operations':'enterprise',
    'property, facilities & asset operations':'property','innovation, venture & product systems':'innovation',
    'energy & environmental systems':'energy','knowledge & institutional systems':'knowledge'
  },
  // metric-registry.json — canonical keys + alias -> canonical (drift prevention)
  metric_keys: ['occupied_pct','leased_pct','trend_pct','total_units','available','vacant_unrented','down','average_rent','average_sqft','workorders_overdue','workorders_unassigned','lead_reply_sec','sms_chat_sec','calls','process_completed','process_pending','process_total','process_performance_pct','cpi','spi_trend','schedule_pct_complete','budget_health_pct','open_rfis_overdue'],
  metric_aliases: { 'occpct':'occupied_pct','occupancy':'occupied_pct','occpercent':'occupied_pct','occupancy %':'occupied_pct','leasedpct':'leased_pct','trendpct':'trend_pct','units':'total_units','vacantunrented':'vacant_unrented','averagerent':'average_rent','averagesqft':'average_sqft','overdue':'workorders_overdue','unassigned':'workorders_unassigned','leadreply':'lead_reply_sec','smschat':'sms_chat_sec','completed':'process_completed','pending':'process_pending','total':'process_total','performance':'process_performance_pct' }
};

const d = $input.first().json;
const violations = [];

// decision-contract: decision_id required (dedupe key)
if (d.decision_id == null || d.decision_id === '') violations.push('missing_field:decision_id');

// decision-contract: entity_key REQUIRED — date-independent Decision->Outcome attribution join
if (d.entity_key == null || d.entity_key === '') violations.push('missing_field:entity_key');

// domain-registry: domain must be a registry ID, not a display name, not ad-hoc
const domainRaw = d.domain == null ? '' : String(d.domain).trim();
const domainLc = domainRaw.toLowerCase();
if (!domainRaw) {
  violations.push('missing_field:domain');
} else if (!CONTRACTS.domain_ids.includes(domainLc)) {
  if (CONTRACTS.domain_names[domainLc]) violations.push("domain_must_be_id_not_name:'"+domainRaw+"'->'"+CONTRACTS.domain_names[domainLc]+"'");
  else violations.push("domain_not_in_registry:'"+domainRaw+"'");
}

// metric-registry: if a metric is named, it must be the canonical key (not alias / unknown)
const metricRaw = d.metric == null ? '' : String(d.metric).trim();
if (metricRaw) {
  const metricLc = metricRaw.toLowerCase();
  if (!CONTRACTS.metric_keys.includes(metricRaw)) {
    if (CONTRACTS.metric_aliases[metricLc]) violations.push("metric_not_canonical:'"+metricRaw+"'->'"+CONTRACTS.metric_aliases[metricLc]+"'");
    else violations.push("metric_unknown:'"+metricRaw+"'");
  }
}

// decision-contract: confidence, if present, must be 0..1
if (d.confidence != null && (typeof d.confidence !== 'number' || d.confidence < 0 || d.confidence > 1)) {
  violations.push("confidence_out_of_range:'"+d.confidence+"'");
}

const valid = violations.length === 0;
const contract = {
  valid,
  registry: CONTRACTS.registry,
  registry_version: CONTRACTS.version,
  registry_frozen_at: CONTRACTS.frozen_at,
  violations,
  status: valid ? 'contract_valid' : 'REJECTED_CONTRACT_VIOLATION',
  validated_at: new Date().toISOString()
};
return [{ json: { ...d, contract, timestamp: d.timestamp || contract.validated_at } }];

// EXECUTE PROPERTY ACTIONS — routes the decision to system actions.
// v1: SIMULATED success. Replace each block with a real HTTP Request / Notion
// node when Yardi (Voyager API) + CRM IQ (fresh loginguid) access is available.
const d = $input.first().json;
const action = String(d.recommended_action || '').toLowerCase();
const executed = [];

// Maintenance acceleration → Yardi work orders
// REAL: POST {yardi}/workorders/create  { priority, unit, category, notes }
if (/maintenance|backlog/.test(action)) {
  executed.push({ system:'Yardi', action:'reprioritize_work_orders', payload:{ priority:'high', category:'turnover acceleration', notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
// Leasing acceleration → CRM IQ tasks
// REAL: POST {crmiq}/tasks  { type:'leasing_follow_up', cadence:'increased' }
if (/leasing|outreach|tour/.test(action)) {
  executed.push({ system:'CRM_IQ', action:'create_task_batch', payload:{ type:'leasing_follow_up', cadence:'increased', notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
// Vacancy / unit readiness → Yardi unit status
if (/occupancy|vacancy|readiness|turnover/.test(action)) {
  executed.push({ system:'Yardi', action:'update_unit_readiness', payload:{ notes:'AI PMO decision '+d.decision_id }, result:'success' });
}
if (!executed.length) executed.push({ system:'none', action:'noop', result:'no_matching_route' });

// Notion audit record (persisted downstream by the 'Save Audit — Executed' Notion node)
const audit = {
  decision_id: d.decision_id,
  actions: executed,
  systems: [...new Set(executed.map(e => e.system))],
  execution_hash: d.execution_hash,
  timestamp: new Date().toISOString()
};
return [{ json: { ...d, executed, audit } }];

// EXECUTION VERIFICATION — confirm each action landed.
const d = $input.first().json;
const acts = d.executed || [];
const verified = acts.filter(e => e.result === 'success');
const failed = acts.filter(e => e.result !== 'success' && e.system !== 'none');
let execution_status = 'success';
if (failed.length && verified.length) execution_status = 'partial';
else if (!verified.length) execution_status = 'failed';
return [{ json: { ...d, verification: { execution_status, verified_actions: verified.map(v => v.system+':'+v.action), failed_actions: failed.map(f => f.system+':'+f.action) } } }];

// CIRO FEEDBACK — the record that feeds the Outcome Attribution layer.
const d = $input.first().json;
const feedback = {
  decision_id: d.decision_id,
  domain: d.domain,
  execution_result: d.verification.execution_status,
  systems_updated: d.verification.verified_actions,
  execution_hash: d.execution_hash,
  guardian: d.guardian,
  contract: d.contract,
  audit: d.audit,
  timestamp: new Date().toISOString(),
  status: d.verification.execution_status === 'success' ? 'verified' : 'review'
};
return [{ json: feedback }];

// Blocked by GUARDiAN — return the rejection reason (no execution).
const d = $input.first().json;
return [{ json: { decision_id: d.decision_id, domain: d.domain, status: 'blocked', guardian: d.guardian, execution_hash: d.execution_hash, timestamp: new Date().toISOString() } }];
